{
  "grant_type": "client_credentials",
  "client_id": "{{clientId}}",
  "client_secret": "{{clientSecret}}"
}

{
  "comments": "Booking created in error" // Optional reason for deleting the booking
}

{
  "uniqueId": "afb0feb2-383d-415c-bcbe-9e1644ec2598" // (required) Unique ID of the draft booking to publish
}

{
  "name": "Sports Group Booking",         // New title for the booking (optional)
  "comments": "Customer has not visited before", // Updated detail (optional, max 500 chars)
  "metadata": {                           // Key-value pairs to merge; set value to null to remove (optional)
    "reservationSource": "partner-portal",
    "groupId": null
  },
  "newItems": [                           // New booking items to add (optional)
    {
      "productId": 153444,
      "quantity": 1,
      "bookingDate": "2025-07-01",
      "startTime": "14:00"
    }
  ],
  "idsToRemove": [],                      // bookingItemIds of items to remove (optional)
  "itemsToUpdate": []                     // Booking items to update fields on (optional)
}

{
  "items": [                   // (required) Products being purchased (booking items)
    {
      "productId": 153444,
      "quantity": 2,
      "bookingDate": "2025-07-01",
      "startTime": "14:00"
    }
  ]
}

{
  "codes": [                     // (required) List of codes to add to the discount (max 1000, max 32 chars each)
    "SUMMER10",
    "SUMMER20"
  ]
}

{
  "codes": [                     // (required) List of codes to delete from the discount
    "SUMMER10"
  ]
}

{
  "externalId": "RESELLER-ORDER-2026-0045",   // (required) External reference, unique per venue; acts as an idempotency key (max 64 chars)
  "productId": 9573,                           // (required) ID of the gift card product to create cards from
  "bookingOwner": {                            // (required) Primary contact for the created booking
    "firstName": "Jordan",
    "lastName": "Avery",
    "email": "jordan.avery@acme-resellers.com",
    "phone": "+61 400 123 456"
  },
  "giftCards": [                               // (required) One entry per card to create (min 1)
    {
      "value": 50,                             // Card value; required for open-value products, omit for fixed-value
      "recipient": {                           // Who the card is addressed to (optional)
        "name": "Sam Rivera",
        "email": "sam.rivera@example.com",
        "message": "Happy birthday! Enjoy a day out on us.",
        "deliveryDateTime": "2026-12-24T09:00:00Z"
      }
    },
    {
      "value": 25,
      "giftCardNumber": "ACME-PROMO-000124",   // Optional custom number (6-128 chars), unique within request and venue
      "recipient": {
        "name": "Alex Chen",
        "email": "alex.chen@example.com"
      }
    }
  ],
  "sendConfirmations": false,                  // Send the booking confirmation to the booking owner (optional)
  "sendGiftCardEmails": true                   // Send each recipient their gift card email (optional)
}

{
  "giftCardNumber": "2606947188" // (required) The gift card code (unique identifier)
}

{
  "name": "Gift Shop T-Shirt",    // (required) Name of the stock product
  "productCategory": "Merchandise", // Product category (optional)
  "externalId": "EXT-TSHIRT-001", // External identifier for the product (optional)
  "products": [                   // (required) Product variations / children
    {
      "name": "Small",
      "price": 29.95,
      "quantity": 50,
      "externalId": "EXT-TSHIRT-S" // (required for new variations) External ID
    }
  ]
}

{
  "parentProductId": "153444",    // (required) Parent product ID
  "name": "Gift Shop T-Shirt",    // Product name (all fields must be included even if not changing)
  "productCategory": "Merchandise", // Product category
  "products": [                   // Product variations / children
    {
      "productId": 245252,         // (required for existing variation) Child product ID
      "name": "Small",
      "price": 32.95,
      "quantity": 40
    }
  ]
}

{
  "productId": 245252,             // (required) Unique productId of the child product
  "quantity": 100                  // New stock quantity (set to null for unlimited)
}

{
  "tickets": [                     // List of tickets to redeem (max 10, must be unique per request)
    {
      "ticketId": "3288921-29937813", // (required) ROLLER ticket ID or customTicketId
      "redemptionDate": "2025-07-01T09:00:00+00:00" // Optional UTC datetime; defaults to now
    }
  ],
  "redemptionDevice": "Front Gate Scanner" // Optional device name where ticket is redeemed
}

{
  "amount": 32.2,                  // (required) Amount payable via the payment link
  "email": "finn.mertons@roller.com", // Recipient email (required if phone not provided)
  "phone": null                    // Recipient phone for SMS (required if email not provided; takes priority over email)
}

{
  "externalId": "UJJSK28374",           // (required) 3rd party booking reference
  "customer": {                           // (required) Booking owner / primary contact
    "firstName": "Jane",
    "lastName": "Smith",
    "email": "jane.smith@example.com"
  },
  "items": [                              // (required) Products being purchased
    {
      "productId": 153444,
      "quantity": 2,
      "bookingDate": "2025-07-01"
    }
  ],
  "discounts": [                          // Discount codes to apply (optional)
    { "code": "SUMMER10" }
  ],
  "giftCards": [],                        // Gift cards to apply (optional)
  "customerPaysFees": false               // Whether to apply ROLLER fees (optional)
}

{
  "url": "https://your-url-to-receive-webhook.com/endpoint", // (required) Endpoint URL to receive webhook events
  "enabled": true,                // (required) Must be true to make the webhook active
  "authentication": {             // Authentication config for the webhook (optional)
    "apiKey": "your-api-key"
  },
  "webhooks": {                   // (required) At least one webhook type must be configured
    "booking": {
      "events": ["Created", "Updated", "Cancelled"],
      "include": {
        "externalId": true,
        "tickets": true,
        "metadata": true
      },
      "filter": {
        "channels": ["VenueManager"],
        "productTypes": ["Pass"]
      }
    }
  }
}

{
  "url": "https://your-url-to-receive-webhook.com/endpoint", // Updated endpoint URL
  "enabled": true,                // Whether the webhook is active
  "authentication": {             // Updated authentication config (optional)
    "apiKey": "your-updated-api-key"
  },
  "webhooks": {                   // Updated webhook event configuration
    "booking": {
      "events": ["Created"],
      "include": {
        "externalId": true,
        "tickets": true,
        "membershipDetail": true,
        "locations": true,
        "customerFlags": true,
        "metadata": true
      },
      "filter": {
        "channels": ["VenueManager"],
        "productTypes": ["Pass"]
      }
    }
  }
}

{
  "exportType": "RevenueEntries",  // (required) Type of data to export: RevenueEntries, Customers, Attendance, Payments, MembershipRedemptions, MembershipStatuses, MembershipCredits, Tickets, Giftcards, BookingItems, PosTillReconciliations, SignedWaivers, BookingSignedWaivers
  "startDate": "2025-07-01",       // (required) Start date inclusive (yyyy-MM-dd)
  "endDate": "2025-07-31"          // (required) End date exclusive (yyyy-MM-dd); must be at least 1 day after startDate
}
